// src/web/test/client.rs

use crate::http::{Request, Response, Method};
use crate::service::Service;

/// Test client for making requests to a router.
///
/// # Example
/// ```rust
/// #[tokio::test]
/// async fn test_api() {
///     let app = Router::new()
///         .get("/users", list_users)
///         .post("/users", create_user);
///
///     let client = TestClient::new(app);
///
///     let response = client.get("/users").await;
///     response.assert_status(200);
///     response.assert_json_contains("users");
/// }
/// ```
pub struct TestClient<S> {
    service: S,
    default_headers: HeaderMap,
}

impl<S> TestClient<S>
where
    S: Service<Request, Response = Response> + Clone,
{
    /// Create a new test client wrapping a service.
    pub fn new(service: S) -> Self {
        Self {
            service,
            default_headers: HeaderMap::new(),
        }
    }

    /// Set a default header for all requests.
    pub fn default_header(mut self, name: &str, value: &str) -> Self {
        self.default_headers.insert(
            name.parse().unwrap(),
            value.parse().unwrap(),
        );
        self
    }

    /// Create a GET request builder.
    pub fn get(&self, uri: &str) -> TestRequestBuilder<S> {
        TestRequestBuilder::new(self.service.clone(), Method::GET, uri)
            .headers(self.default_headers.clone())
    }

    /// Create a POST request builder.
    pub fn post(&self, uri: &str) -> TestRequestBuilder<S> {
        TestRequestBuilder::new(self.service.clone(), Method::POST, uri)
            .headers(self.default_headers.clone())
    }

    /// Create a PUT request builder.
    pub fn put(&self, uri: &str) -> TestRequestBuilder<S> {
        TestRequestBuilder::new(self.service.clone(), Method::PUT, uri)
            .headers(self.default_headers.clone())
    }

    /// Create a PATCH request builder.
    pub fn patch(&self, uri: &str) -> TestRequestBuilder<S> {
        TestRequestBuilder::new(self.service.clone(), Method::PATCH, uri)
            .headers(self.default_headers.clone())
    }

    /// Create a DELETE request builder.
    pub fn delete(&self, uri: &str) -> TestRequestBuilder<S> {
        TestRequestBuilder::new(self.service.clone(), Method::DELETE, uri)
            .headers(self.default_headers.clone())
    }

    /// Create a request with any method.
    pub fn request(&self, method: Method, uri: &str) -> TestRequestBuilder<S> {
        TestRequestBuilder::new(self.service.clone(), method, uri)
            .headers(self.default_headers.clone())
    }
}
